import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface BodyCompositionData {
  current: {
    weight: number;
    bodyFatPercentage: number;
    muscleMass: number;
  };
  threeMonthTrend: {
    dates: string[];
    weightTrend: number[];
    bodyFatTrend: number[];
    muscleMassTrend: number[];
  };
}

export default function Widget() {
  const data = response.data as BodyCompositionData;
  const { current, threeMonthTrend } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1C1C1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#B0BEC5' }}>
              Current Stats
            </Typography>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FFFFFF', mb: 0.5 }}>
              Weight: {current.weight} lbs
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Body Fat: {current.bodyFatPercentage}%
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Muscle Mass: {current.muscleMass} lbs
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: threeMonthTrend.weightTrend,
                  color: '#FF5252',
                  label: 'Weight',
                  curve: 'linear',
                },
                {
                  type: 'line',
                  data: threeMonthTrend.bodyFatTrend,
                  color: '#FFCA28',
                  label: 'Body Fat',
                  curve: 'linear',
                },
                {
                  type: 'line',
                  data: threeMonthTrend.muscleMassTrend,
                  color: '#4CAF50',
                  label: 'Muscle Mass',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: threeMonthTrend.dates,
                  id: 'months',
                },
              ]}
              yAxis={[{ id: 'metrics' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="months"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="metrics"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
